import type { Meta, StoryObj } from '@storybook/react-vite';
import { Divider } from './Divider';
import { Text } from '../Text';

const meta = {
  title: 'Components/Divider',
  component: Divider,
  tags: ['autodocs'],
  argTypes: {
    direction: { control: 'inline-radio', options: ['horizontal', 'vertical'] },
    contentPosition: { control: 'inline-radio', options: ['left', 'center', 'right'] },
    borderStyle: { control: 'select', options: ['solid', 'dashed', 'dotted'] },
  },
  args: {
    direction: 'horizontal',
    contentPosition: 'center',
  },
} satisfies Meta<typeof Divider>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Basic: Story = {
  render: (args) => (
    <div style={{ width: 360 }}>
      <Text>Section one</Text>
      <Divider {...args} />
      <Text>Section two</Text>
    </div>
  ),
};

export const WithText: Story = {
  name: 'With text',
  render: () => (
    <div style={{ width: 360 }}>
      <Divider contentPosition="left">Left</Divider>
      <Divider>Center</Divider>
      <Divider contentPosition="right">Right</Divider>
    </div>
  ),
};

export const Dashed: Story = {
  render: () => (
    <div style={{ width: 360 }}>
      <Text>Above</Text>
      <Divider borderStyle="dashed" />
      <Text>Below</Text>
    </div>
  ),
};

export const Vertical: Story = {
  render: () => (
    <div style={{ display: 'flex', alignItems: 'center' }}>
      <Text>Home</Text>
      <Divider direction="vertical" />
      <Text>Docs</Text>
      <Divider direction="vertical" />
      <Text>About</Text>
    </div>
  ),
};

import { type CSSProperties, forwardRef, type HTMLAttributes, type ReactNode } from 'react';
import { cls, useNamespace } from '../../utils';

export type DividerDirection = 'horizontal' | 'vertical';

export type DividerContentPosition = 'left' | 'center' | 'right';

export interface DividerProps extends HTMLAttributes<HTMLDivElement> {
  /** Divider orientation. */
  direction?: DividerDirection;
  /** Position of the text label (horizontal direction only). */
  contentPosition?: DividerContentPosition;
  /** Border line style. */
  borderStyle?: CSSProperties['borderStyle'];
  children?: ReactNode;
}

export const Divider = forwardRef<HTMLDivElement, DividerProps>(function Divider(props, ref) {
  const {
    direction = 'horizontal',
    contentPosition = 'center',
    borderStyle = 'solid',
    className,
    style,
    children,
    ...rest
  } = props;

  const ns = useNamespace('divider');

  const classes = cls(
    ns.b(),
    ns.m(direction),
    direction === 'horizontal' && ns.is(contentPosition),
    className,
  );

  const dividerStyle = {
    '--ec-divider-border-style': borderStyle,
    ...style,
  } as CSSProperties;

  return (
    <div
      ref={ref}
      className={classes}
      style={dividerStyle}
      role="separator"
      aria-orientation={direction}
      {...rest}
    >
      {direction === 'horizontal' && children !== undefined && children !== null && (
        <span className={ns.e('text')}>{children}</span>
      )}
    </div>
  );
});

.ec-divider {
  --ec-divider-border-color: var(--ec-border-color);
  --ec-divider-border-style: solid;
  --ec-divider-text-bg-color: var(--ec-bg-color);
  --ec-divider-text-color: var(--ec-text-color-primary);
  --ec-divider-text-font-size: var(--ec-font-size-small);

  box-sizing: border-box;
  position: relative;
}

/* ---- Horizontal ---- */
.ec-divider--horizontal {
  display: block;
  width: 100%;
  margin: 24px 0;
  border-top: var(--ec-border-width) var(--ec-divider-border-style) var(--ec-divider-border-color);
}

.ec-divider--horizontal .ec-divider__text {
  position: absolute;
  top: 50%;
  box-sizing: border-box;
  padding: 0 20px;
  font-size: var(--ec-divider-text-font-size);
  font-weight: var(--ec-font-weight-primary);
  color: var(--ec-divider-text-color);
  background-color: var(--ec-divider-text-bg-color);
  transform: translateY(-50%);
}

.ec-divider--horizontal.is-left .ec-divider__text {
  left: 20px;
  transform: translateY(-50%);
}

.ec-divider--horizontal.is-center .ec-divider__text {
  left: 50%;
  transform: translate(-50%, -50%);
}

.ec-divider--horizontal.is-right .ec-divider__text {
  right: 20px;
  left: auto;
  transform: translateY(-50%);
}

/* ---- Vertical ---- */
.ec-divider--vertical {
  display: inline-block;
  width: 0;
  height: 1em;
  margin: 0 8px;
  vertical-align: middle;
  border-left: var(--ec-border-width) var(--ec-divider-border-style) var(--ec-divider-border-color);
}
